package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.NoSuchElementException;

class GsonTypesTest {

    @Test
    void indexOf_foundElement_returnsCorrectIndex() throws Exception {
        Object[] array = {"a", "b", "c"};
        Object toFind = "b";

        Method indexOfMethod = getIndexOfMethod();
        int result = (int) indexOfMethod.invoke(null, array, toFind);

        assertEquals(1, result);
    }

    @Test
    void indexOf_firstElement_returnsZero() throws Exception {
        Object[] array = {"x", "y", "z"};
        Object toFind = "x";

        Method indexOfMethod = getIndexOfMethod();
        int result = (int) indexOfMethod.invoke(null, array, toFind);

        assertEquals(0, result);
    }

    @Test
    void indexOf_lastElement_returnsLastIndex() throws Exception {
        Object[] array = {"x", "y", "z"};
        Object toFind = "z";

        Method indexOfMethod = getIndexOfMethod();
        int result = (int) indexOfMethod.invoke(null, array, toFind);

        assertEquals(2, result);
    }

    @Test
    void indexOf_elementNotFound_throwsNoSuchElementException() throws Exception {
        Object[] array = {"a", "b", "c"};
        Object toFind = "d";

        Method indexOfMethod = getIndexOfMethod();

        InvocationTargetException thrown = assertThrows(InvocationTargetException.class, () -> {
            indexOfMethod.invoke(null, array, toFind);
        });
        assertTrue(thrown.getCause() instanceof NoSuchElementException);
    }

    @Test
    void indexOf_nullElement_throwsNullPointerException() throws Exception {
        Object[] array = {"a", null, "c"};
        Object toFind = null;

        Method indexOfMethod = getIndexOfMethod();

        InvocationTargetException thrown = assertThrows(InvocationTargetException.class, () -> {
            indexOfMethod.invoke(null, array, toFind);
        });
        // Because toFind.equals(array[i]) will throw NullPointerException if toFind is null
        assertTrue(thrown.getCause() instanceof NullPointerException);
    }

    private Method getIndexOfMethod() throws NoSuchMethodException {
        Method method = $Gson$Types.class.getDeclaredMethod("indexOf", Object[].class, Object.class);
        method.setAccessible(true);
        return method;
    }
}
